import React, { useEffect, useState } from 'react';
import { api } from '../api/api';

interface HomePageProps {
    onRequest?: () => void;
}

interface Product {
    id: number;
    name: string;
    description: string;
    image_url: string;
    price: number;
}

interface Service {
    id: number;
    title: string;
    description: string;
    icon: string;
    price: string;
}

const HomePage: React.FC<HomePageProps> = ({ onRequest }) => {
    const [featuredProducts, setFeaturedProducts] = useState<Product[]>([]);
    const [services, setServices] = useState<Service[]>([]);
    const [loading, setLoading] = useState<boolean>(true);

    useEffect(() => {
        Promise.all([api.getProducts(), api.getServices()])
            .then(([products, servicesData]) => {
                setFeaturedProducts(products.slice(0, 3));
                setServices(servicesData.slice(0, 3));
                setLoading(false);
            })
            .catch((err) => {
                console.error(err);
                setLoading(false);
            });
    }, []);

    return (
        <div>
            {/* ===== HERO ===== */}
            <section className="bg-gradient-to-r from-blue-500 to-indigo-600 text-white py-20">
                <div className="container mx-auto px-4 text-center">
                    <h1 className="text-5xl font-bold mb-4">Каталог нашей продукции</h1>
                    <p className="text-xl max-w-3xl mx-auto">
                        Российский производитель и разработчик коммутационных изделий для
                        цепей управления, контроля, сигнализации и диагностики.
                    </p>
                    {onRequest && (
                        <button
                            type="button"
                            onClick={onRequest}
                            className="mt-6 bg-white text-blue-600 px-6 py-3 rounded-full font-semibold hover:bg-gray-100 transition"
                        >
                            Оставить заявку
                        </button>
                    )}
                </div>
            </section>

            {/* ===== ПРОДУКЦИЯ (первые 3) ===== */}
            <section className="py-12 bg-gray-50">
                <div className="container mx-auto px-4">
                    <h2 className="text-3xl font-bold text-center mb-8">Наша продукция</h2>
                    {loading ? (
                        <div className="text-center text-gray-500">Загрузка...</div>
                    ) : (
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            {featuredProducts.map((product) => (
                                <div
                                    key={product.id}
                                    className="bg-white rounded-lg shadow p-4 hover:shadow-lg transition"
                                >
                                    <img
                                        src={product.image_url || 'https://via.placeholder.com/200'}
                                        alt={product.name}
                                        className="w-full h-40 object-contain mb-3"
                                    />
                                    <h3 className="font-semibold">{product.name}</h3>
                                    <p className="text-sm text-gray-600">{product.description}</p>
                                    <p className="text-green-600 font-bold mt-2">{product.price} ₽</p>
                                </div>
                            ))}
                        </div>
                    )}
                    <div className="text-center mt-6">
                        <a
                            href="#/catalog"
                            className="inline-block bg-green-600 text-white px-6 py-2 rounded hover:bg-green-700 transition"
                        >
                            Весь каталог
                        </a>
                    </div>
                </div>
            </section>

            {/* ===== УСЛУГИ (первые 3, как на макете) ===== */}
            <section className="py-12 bg-white">
                <div className="container mx-auto px-4">
                    <h2 className="text-3xl font-bold text-center mb-8">Наши услуги</h2>
                    {loading ? (
                        <div className="text-center text-gray-500">Загрузка...</div>
                    ) : (
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            {services.map((service) => (
                                <div
                                    key={service.id}
                                    className="bg-gray-50 rounded-lg p-6 text-center hover:shadow-lg transition border-t-4 border-green-500"
                                >
                                    <div className="text-4xl mb-3">{service.icon || '🔧'}</div>
                                    <h3 className="text-xl font-semibold">{service.title}</h3>
                                    <p className="text-gray-600 mt-2">{service.description}</p>
                                    <p className="text-green-600 font-bold mt-3">{service.price}</p>
                                </div>
                            ))}
                        </div>
                    )}
                    <div className="text-center mt-6">
                        <a
                            href="#/services"
                            className="inline-block bg-green-600 text-white px-6 py-2 rounded hover:bg-green-700 transition"
                        >
                            Все услуги
                        </a>
                    </div>
                </div>
            </section>

            {/* ===== О НАС (с таймлайном) ===== */}
            <section className="py-16 sm:py-20 bg-gray-100">
                <div className="container-page">
                    <div className="surface-card p-6 sm:p-10 lg:p-12">
                        <div className="grid gap-8 lg:grid-cols-[.8fr_1.2fr] lg:items-start">
                            <div>
                                <span className="kicker">О нас</span>
                                <h2 className="mt-5 font-display text-3xl font-black tracking-tight text-graphite-950 sm:text-5xl">
                                    Более 60 лет лидерства
                                </h2>
                                <p className="mt-3 text-sm text-graphite-500">Ключевые вехи истории завода</p>
                            </div>
                            <div className="space-y-5 text-base leading-8 text-graphite-600">
                                <p>
                  <span className="font-bold text-factory-700">
                    ОАО «Смоленский завод радиодеталей»
                  </span>
                                    , основанное в <span className="font-bold text-factory-700">1961 году</span>, и
                                    более 60 лет является одним из крупнейших предприятий, выпускающих
                                    коммутационные и установочные изделия.
                                </p>
                                <p>
                                    Постановлением Совета Министров РСФСР №106-1 от{' '}
                                    <span className="font-bold text-factory-700">29 января 1959 года</span> началось
                                    строительство завода радиодеталей по производству коммутационных и
                                    установочных изделий в Смоленске. В октябре{' '}
                                    <span className="font-bold text-factory-700">1961 года</span> Смоленский завод
                                    радиодеталей вступил в строй действующих.
                                </p>
                                <p>
                                    В <span className="font-bold text-factory-700">1976 году</span> заводу присвоено
                                    имя «Смоленский завод имени XXV партсъезда». В{' '}
                                    <span className="font-bold text-factory-700">1979 году</span> вошел в состав НПО
                                    «Феникс».
                                </p>
                                <p>
                                    В <span className="font-bold text-factory-700">1994 году</span> реорганизован в
                                    АООТ «Смоленский завод радиодеталей». В{' '}
                                    <span className="font-bold text-factory-700">2002 году</span> переименован в ОАО
                                    «Смоленский завод радиодеталей».
                                </p>
                            </div>
                        </div>

                        {/* Таймлайн */}
                        <div className="mt-10 pt-8 border-t border-graphite-200">
                            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-3">
                                {[
                                    { year: '1959', event: 'Начало строительства' },
                                    { year: '1961', event: 'Ввод в эксплуатацию' },
                                    { year: '1976', event: 'Присвоение имени' },
                                    { year: '1979', event: 'Вхождение в НПО «Феникс»' },
                                    { year: '1994', event: 'Реорганизация в АООТ' },
                                    { year: '2002', event: 'Переименование в ОАО' },
                                ].map((item, index) => (
                                    <div
                                        key={index}
                                        className="bg-graphite-50 rounded-xl p-3 text-center hover:shadow-md transition-shadow border border-graphite-100"
                                    >
                                        <div className="text-lg font-bold text-factory-700">{item.year}</div>
                                        <div className="text-xs text-graphite-500 leading-tight">{item.event}</div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default HomePage;
